"use client";

import { useState, useEffect, useMemo } from "react";
import { Document, Page, pdfjs } from "react-pdf";

import "react-pdf/dist/Page/TextLayer.css";
import "react-pdf/dist/Page/AnnotationLayer.css";

// PDF worker
pdfjs.GlobalWorkerOptions.workerSrc = "/pdf.worker.min.mjs";

export default function PDFViewer({
  page,
  highlight,
}: {
  page: number;
  highlight?: string;
}) {
  const [pdfFile, setPdfFile] = useState<File | null>(null);
  const [numPages, setNumPages] = useState<number>(0);

  // When PDF loads
  const onDocumentLoadSuccess = ({ numPages }: { numPages: number }) => {
    setNumPages(numPages);
  };

  // Memoized options (prevents unnecessary reloads)
  const pdfOptions = useMemo(() => {
    return {
      cMapUrl: "cmaps/",
      cMapPacked: true,
    };
  }, []);

  /*
  =============================
  SCROLL TO SELECTED PAGE
  =============================
  */
  useEffect(() => {
    if (!page) return;

    const pageElement = document.querySelector(
      `[data-page-number="${page}"]`
    );

    if (pageElement) {
      pageElement.scrollIntoView({
        behavior: "smooth",
        block: "center",
      });
    }
  }, [page]);

  /*
  =============================
  HIGHLIGHT PARAGRAPH
  =============================
  */
  useEffect(() => {
    if (!highlight) return;

    const timer = setTimeout(() => {
      const textSpans = document.querySelectorAll(
        ".react-pdf__Page__textContent span"
      );

      // reset previous highlights
      textSpans.forEach((span) => {
        (span as HTMLElement).style.background = "";
      });

      textSpans.forEach((span) => {
        const text = span.textContent?.toLowerCase() || "";
        const target = highlight.toLowerCase();

        if (text && target.includes(text)) {
          (span as HTMLElement).style.background = "yellow";
          (span as HTMLElement).style.borderRadius = "3px";
        }
      });
    }, 500);

    return () => clearTimeout(timer);
  }, [page, highlight]);

  /*
  =============================
  UPLOAD PDF
  =============================
  */
  const uploadPDF = async (file: File) => {
    const formData = new FormData();
    formData.append("file", file);

    await fetch("http://127.0.0.1:8000/upload", {
      method: "POST",
      body: formData,
    });

    setPdfFile(file);
  };

  return (
    <main className="flex-1 bg-[#1e232e] p-6 flex flex-col">
      <h2 className="text-xl mb-4 text-white">PDF Viewer</h2>

      {/* Upload */}
      <input
        type="file"
        accept="application/pdf"
        onChange={(e) => {
          if (e.target.files) uploadPDF(e.target.files[0]);
        }}
        className="mb-4 text-white"
      />

      {/* PDF Viewer */}
      <div className="flex-1 bg-white rounded overflow-auto p-4 flex justify-center">
        {pdfFile ? (
          <Document
            file={pdfFile}
            options={pdfOptions}
            onLoadSuccess={onDocumentLoadSuccess}
          >
            {Array.from(new Array(numPages), (_, index) => (
              <div key={index} data-page-number={index + 1}>
                <Page
                  pageNumber={index + 1}
                  renderTextLayer={true}
                  renderAnnotationLayer={true}
                />
              </div>
            ))}
          </Document>
        ) : (
          <div className="flex items-center justify-center h-full text-black">
            Upload a PDF to begin
          </div>
        )}
      </div>
    </main>
  );
}




