"use client";

import { useState } from "react";

interface Source {
  text: string;
  page: number;
  filename: string;
}

interface Message {
  role: "user" | "assistant";
  content: string;
  sources?: Source[];
}

export default function ChatPanel({
  setPage,
  setHighlight,
}: {
  setPage: (p: number) => void;
  setHighlight: (text: string) => void;
}) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");

  const sendMessage = async () => {
    if (!input.trim()) return;

    const newMessages = [...messages, { role: "user" as const, content: input }];
    setMessages(newMessages);
    setInput("");

    const aiMessage: Message = { role: "assistant", content: "" };
    setMessages((prev) => [...prev, aiMessage]);

    const response = await fetch("http://127.0.0.1:8000/ask-stream", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        query: input,
        history: newMessages,
      }),
    });

    if (!response.body) {
      console.error("No response body from server");
      return;
    }

    const reader = response.body.getReader();
    const decoder = new TextDecoder();

    let fullText = "";

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      const chunk = decoder.decode(value);
      fullText += chunk;

      setMessages((prev) => {
        const updated = [...prev];
        updated[updated.length - 1] = {
          role: "assistant",
          content: fullText,
        };
        return updated;
      });
    }

    // Fetch sources after streaming finishes
    const sourceResponse = await fetch("http://127.0.0.1:8000/ask", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        query: input,
        history: newMessages,
      }),
    });

    const data = await sourceResponse.json();

    setMessages((prev) => {
      const updated = [...prev];
      updated[updated.length - 1] = {
        role: "assistant",
        content: fullText,
        sources: data.sources,
      };
      return updated;
    });
  };

  return (
    <aside className="w-96 bg-[#1a212e] border-l border-[#282e39] p-4 flex flex-col">
      
      {/* CHAT */}
      <div className="flex-1 overflow-y-auto space-y-4">
        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
            
            <div
              className={`p-3 rounded-lg max-w-xs ${
                msg.role === "user"
                  ? "bg-cyan-600"
                  : "bg-[#102022] border border-[#282e39]"
              }`}
            >
              {msg.content}

              {/* SOURCES */}
              {msg.role === "assistant" && msg.sources && (
                <div className="mt-3 space-y-2">

                  <div className="text-xs text-gray-400">
                    Sources
                  </div>

                  {msg.sources.map((src, idx) => (
                    <div
                      key={idx}
                      onClick={() => {
                        setPage(src.page);
                        setHighlight(src.text);
                      }}
                      className="p-2 border border-[#282e39] rounded text-xs cursor-pointer hover:bg-[#0f1720]"
                    >
                      <div className="text-cyan-400">
                        {src.filename}
                      </div>

                      <div className="text-gray-400">
                        Page {src.page}
                      </div>

                      <div className="text-gray-500 line-clamp-2">
                        {src.text}
                      </div>

                    </div>
                  ))}

                </div>
              )}

            </div>

          </div>
        ))}
      </div>

      {/* INPUT */}
      <div className="mt-4 flex gap-2">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") sendMessage();
          }}
          className="flex-1 p-2 rounded bg-[#102022] border border-[#282e39]"
          placeholder="Ask something..."
        />

        <button onClick={sendMessage} className="bg-cyan-500 px-4 rounded">
          Send
        </button>
      </div>
    </aside>
  );
}